// @n8n-evol-I:primitive — exempt from pure-function discipline
// Active cleanup: iterate every queue stream the env has registered, KEYS
// the q:<stream>:permits:* glob, then GET each sidecar and DECR inflight +
// DEL the permit only when sidecar.execution_id matches the failed run.
// We deliberately do NOT XACK — the message stays in the PEL and is
// redelivered by the next XAUTOCLAIM. The failed run's work was
// incomplete; let the redelivery decide whether to retry or DLQ.
let QUEUE_SCOPES;
try {
  QUEUE_SCOPES = {{@env:queueScopes}};
} catch (e) {
  QUEUE_SCOPES = [];
}
if (!Array.isArray(QUEUE_SCOPES)) QUEUE_SCOPES = [];

const errorData = $('Error Trigger').first().json || {};
const failed_execution_id = errorData.execution?.id || errorData.executionId || $execution.id || 'unknown';
const failed_workflow_id = errorData.workflow?.id || 'unknown';
const failed_workflow_name = errorData.workflow?.name || 'unknown';
const failed_error_message = errorData.execution?.error?.message || errorData.error?.message || 'unknown';

if (QUEUE_SCOPES.length === 0) {
  return [{
    json: {
      cleaned: false,
      reason: 'no queueScopes registered in env yaml — add to queueScopes list to enable active cleanup',
      failed_execution_id,
      failed_workflow_id,
      failed_workflow_name,
      failed_error_message,
      cleanup_terminal: true,
    },
  }];
}

return QUEUE_SCOPES.map(stream => ({
  json: {
    stream,
    permits_glob: `q:${stream}:permits:*`,
    inflight_key: `q:${stream}:inflight`,
    failed_execution_id,
    failed_workflow_id,
    failed_workflow_name,
    failed_error_message,
    cleanup_terminal: false,
  },
}));

// @n8n-evol-I:primitive — exempt from pure-function discipline
// For each per-stream KEYS result, fan the returned permit keys back into
// individual items, propagating per-stream context (inflight_key,
// failed_execution_id, etc.) onto each.
const items = $input.all();
const streamCtx = $('Prepare Stream List').all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const keysResp = items[i].json;
  const ctx = streamCtx[i] && streamCtx[i].json;
  if (!ctx) continue;
  const keysArr = Array.isArray(keysResp.result) ? keysResp.result : [];
  for (const permit_key of keysArr) {
    out.push({
      json: {
        permit_key,
        stream: ctx.stream,
        inflight_key: ctx.inflight_key,
        failed_execution_id: ctx.failed_execution_id,
        failed_workflow_id: ctx.failed_workflow_id,
        failed_workflow_name: ctx.failed_workflow_name,
        failed_error_message: ctx.failed_error_message,
      },
    });
  }
}
if (out.length === 0) {
  return [{ json: { cleaned: false, reason: 'no permits found for any registered stream', cleanup_terminal: true } }];
}
return out;

// @n8n-evol-I:primitive — exempt from pure-function discipline
// Parse each sidecar JSON; keep entries where parsed.execution_id matches
// the failed run.
const items = $input.all();
const fanOut = $('Fan Out Permit Keys').all();
const owned = [];
for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const ctx = fanOut[i] && fanOut[i].json;
  if (!ctx || !resp || !resp.result) continue;
  let parsed;
  try {
    parsed = JSON.parse(resp.result);
  } catch (e) {
    continue;
  }
  if (parsed && parsed.execution_id === ctx.failed_execution_id) {
    owned.push({
      json: {
        should_release: true,
        permit_key: ctx.permit_key,
        inflight_key: ctx.inflight_key,
        stream: ctx.stream,
        message_id: parsed.message_id,
        failed_execution_id: ctx.failed_execution_id,
        failed_workflow_id: ctx.failed_workflow_id,
        failed_workflow_name: ctx.failed_workflow_name,
        failed_error_message: ctx.failed_error_message,
      },
    });
  }
}
if (owned.length === 0) {
  return [{ json: { cleaned: false, reason: 'no permits owned by failed execution', cleanup_terminal: true } }];
}
return owned;

// @n8n-evol-I:primitive — exempt from pure-function discipline
const items = $input.all();
const cleaned = items.length > 0 && items.some(i => i.json.should_release === true || i.json.result !== undefined);
const streams = Array.from(new Set(items.map(i => i.json.stream).filter(Boolean)));
return [{
  json: {
    cleaned,
    cleaned_count: items.filter(i => i.json.should_release === true).length,
    streams,
  },
}];
